const data = $input.first().json;
const mp4WithAudio = data.videos.items.find(v => v.hasAudio && v.extension === 'mp4');

return [{
  json: {
    title: data.title,
    videoId: data.id,
    downloadUrl: mp4WithAudio.url,
    quality: mp4WithAudio.quality,
    size: mp4WithAudio.size,
    sizeText: mp4WithAudio.sizeText
  }
}];

